if (!fechaCot) return null; 

const fecha = new Date(`${fechaCot}T00:00:00`);

fecha.setDate(fecha.getDate() + 31);

return fecha.toISOString().slice(0, 10);

const SUBPRODUCTOS = {
  Servicios: "48110",
  Construccion: "48111",
  Eventos: "48112",
  Serviu: "48114",
  MOP: "48115"
};

const subproductoId = this.frmIG_idSubProducto;
const fechaCot = this.frmIG_fechaCotizacion; // "YYYY-MM-DD"

if (!fechaCot) return null;

let fechaMinima;

// Sin retroactividad
if ([SUBPRODUCTOS.Servicios, SUBPRODUCTOS.Eventos].includes(subproductoId)) {
  fechaMinima = fechaCot;
}

// Con retroactividad (30 días)
else if ([SUBPRODUCTOS.Construccion, SUBPRODUCTOS.MOP, SUBPRODUCTOS.Serviu].includes(subproductoId)) {
  const fecha = new Date(`${fechaCot}T00:00:00`);
  fecha.setDate(fecha.getDate() - 30);
  fechaMinima = fecha.toISOString().slice(0, 10);
}

// Fallback seguro
else {
  fechaMinima = fechaCot;
}

return fechaMinima;

const SUBPRODUCTOS = {
  Serviu: "48114",
  MOP: "48115"
};

const subprod = this.frmIG_idSubProducto;

// Fecha inicio (común para todos)
const fechaInicio = this.frmDC_fechaInicioVigencia
  ? new Date(`${this.frmDC_fechaInicioVigencia}T00:00:00`)
  : null;

// Determinar qué fecha fin usar
let fechaFin = null;

if ([SUBPRODUCTOS.Serviu, SUBPRODUCTOS.MOP].includes(subprod)) {
  // MOP / SERVIU → fecha fin calculada MS
  fechaFin = this.frmDC_fechaFinVigenciaMS
    ? new Date(`${this.frmDC_fechaFinVigenciaMS}T00:00:00`)
    : null;
} else {
  // Resto de productos → fecha fin estándar
  fechaFin = this.frmDC_fechaFinVigencia
    ? new Date(`${this.frmDC_fechaFinVigencia}T00:00:00`)
    : null;
}

// Calcular días
let dias = 0;

if (fechaInicio && fechaFin) {
  dias = Math.round(
    (fechaFin.getTime() - fechaInicio.getTime()) / (1000 * 60 * 60 * 24)
  );
}

return dias;


