const SUBPRODUCTOS = {
  Construccion: "48111",
  Serviu: "48114",
  MOP: "48115",
  Servicios: "48110",
  Eventos: "48112"
};

const fechaInicioStr = this.frmDC_fechaInicioVigencia; // YYYY-MM-DD
const subproductoId  = this.frmIG_idSubProducto;

if (!fechaInicioStr) return null;

const fechaInicio = new Date(`${fechaInicioStr}T00:00:00`);
let fechaMin = new Date(fechaInicio);

// Fecha mínima según producto
if (subproductoId === SUBPRODUCTOS.Eventos) {
  // RC Eventos -> 1 día
  fechaMin.setDate(fechaMin.getDate() + 1);
} else {
  // Los demás -> 12 meses
  fechaMin.setMonth(fechaMin.getMonth() + 12);
}

// Formato YYYY-MM-DD
return fechaMin.toISOString().slice(0, 10);

const SUBPRODUCTOS = {
  Construccion: "48111",
  Serviu: "48114",
  MOP: "48115",
  Servicios: "48110",
  Eventos: "48112"
};

const fechaInicioStr = this.frmDC_fechaInicioVigencia; // YYYY-MM-DD
const subproductoId = this.frmIG_idSubProducto;

if (!fechaInicioStr) return null;

const fechaInicio = new Date(`${fechaInicioStr}T00:00:00`);
let fechaMax = new Date(fechaInicio);

// 🔹 Fecha máxima según producto
switch (subproductoId) {
  case SUBPRODUCTOS.Construccion:
    // 36 meses
    fechaMax.setMonth(fechaMax.getMonth() + 36);
    break;

  case SUBPRODUCTOS.Serviu:
  case SUBPRODUCTOS.MOP:
    // 48 meses
    fechaMax.setMonth(fechaMax.getMonth() + 48);
    break;

  case SUBPRODUCTOS.Servicios:
    // 12 meses exactos
    fechaMax.setMonth(fechaMax.getMonth() + 12);
    break;

  case SUBPRODUCTOS.Eventos:
    // 60 días
    fechaMax.setDate(fechaMax.getDate() + 60);
    break;

  default:
    return null;
}

// Formato YYYY-MM-DD
return fechaMax.toISOString().slice(0, 10);

const SUBPRODUCTOS = {
  Servicios: "48110",
  Construccion: "48111",
  Eventos: "48112",
  Serviu: "48114",
  MOP: "48115"
};

// no validar fecha fin para MOP / SERVIU
if ([SUBPRODUCTOS.Serviu, SUBPRODUCTOS.MOP].includes(this.frmIG_idSubProducto)) {
  return this.frmDC_fechaFinVigencia ?? null;
}

const toDate = (s) => s ? new Date(`${s}T00:00:00`) : null;
const fmt = (d) => d ? [
  String(d.getDate()).padStart(2,'0'),
  String(d.getMonth()+1).padStart(2,'0'),
  d.getFullYear()
].join('/') : '—';

// VARIABLES FECHA FIN
const vStr   = this.frmDC_fechaFinVigencia;
const minStr = this.frmDC_fechaFinVigenciaMinima;
const maxStr = this.frmDC_fechaFinVigenciaMaxima;

const v   = toDate(vStr);
const min = toDate(minStr);
const max = toDate(maxStr);

// Aplicar min / max al input
setTimeout(() => {
  const input = document.querySelector('input[name="frmDC_fechaFinVigencia"]');
  if (input) {
    if (minStr) input.setAttribute('min', minStr);
    if (maxStr) input.setAttribute('max', maxStr);
  }
}, 0);

// Si aún no hay datos completos, no validar
if (!v || !min || !max) {
  return this.frmDC_fechaFinVigencia ?? null;
}

const outOfRange = (v < min) || (v > max);

// Feedback visual + modal
setTimeout(() => {
  const input = document.querySelector('input[name="frmDC_fechaFinVigencia"]');
  const group = input?.closest('.form-group');

  if (group) {
    const prev = group.querySelector('.invalid-feedback');
    if (prev) prev.remove();
  }
  input?.classList.remove('is-invalid');

  if (outOfRange) {
    if (input && !input.classList.contains('is-invalid')) {
      input.classList.add('is-invalid');
    }

    if (group && !group.querySelector('.invalid-feedback')) {
      const msg = document.createElement('div');
      msg.className = 'invalid-feedback d-block';

      // MENSAJE ESPECIAL SOLO PARA RC SERVICIOS
      if (this.frmIG_idSubProducto === SUBPRODUCTOS.Servicios) {
        msg.innerHTML = `<div>La fecha debe ser igual a ${fmt(min)}.</div>`;
      } else {
        msg.innerHTML = `<div>La fecha debe estar entre ${fmt(min)} y ${fmt(max)}.</div>`;
      }

      group.insertBefore(msg, group.querySelector('small.form-text'));
    }

    // MISMO MODAL
    const MODAL_ID = 'modal_fecha_invalida';
    const BTN_SEL  = '[custom-css-selector="btn_preventivo"]';
    const now = Date.now();

    window.__iv_lastModalAt = window.__iv_lastModalAt || 0;
    if ((now - window.__iv_lastModalAt) > 600) {
      const boton = document.querySelector(BTN_SEL);
      if (boton?.__vue__?.$root?.$bvModal) {
        boton.__vue__.$root.$bvModal.show(MODAL_ID);
      }
      window.__iv_lastModalAt = now;
    }
  }
}, 250);

// Control de guardado
if (outOfRange) return null;
return this.frmDC_fechaFinVigencia;

const SUBPRODUCTOS = {
  Serviu: "48114",
  MOP: "48115"
};

const inicioStr = this.frmDC_fechaInicioVigencia; // YYYY-MM-DD
const diasObra  = Number(this.frmDC_diasObra);
const diasMant  = Number(this.frmDC_diasMantenimiento);
const subprod   = this.frmIG_idSubProducto;

// Solo aplica a MOP / SERVIU
if (![SUBPRODUCTOS.Serviu, SUBPRODUCTOS.MOP].includes(subprod)) {
  return null;
}

// Validaciones mínimas
if (!inicioStr) return null;
if (isNaN(diasObra) || diasObra < 0) return null;
if (isNaN(diasMant) || diasMant < 0 || diasMant > 548) return null;

// Cálculo de fecha
const inicio = new Date(`${inicioStr}T00:00:00`);
const totalDias = diasObra + diasMant;

inicio.setDate(inicio.getDate() + totalDias);

// Formato YYYY-MM-DD
return inicio.toISOString().slice(0, 10);

const SUBPRODUCTOS = {
  Serviu: "48114",
  MOP: "48115"
};

const subprod   = this.frmIG_idSubProducto;
const inicioStr = this.frmDC_fechaInicioVigencia;
const diasObra  = Number(this.frmDC_diasObra);

// Solo para MOP / SERVIU
if (![SUBPRODUCTOS.Serviu, SUBPRODUCTOS.MOP].includes(subprod)) {
  return null;
}

// Validaciones mínimas para calcular
if (!inicioStr) return null;
if (isNaN(diasObra) || diasObra < 0) return null;

// Calcular fecha fin de obra
const inicio = new Date(`${inicioStr}T00:00:00`);
inicio.setDate(inicio.getDate() + diasObra);

// Retornar YYYY-MM-DD
return inicio.toISOString().slice(0, 10);

const SUBPRODUCTOS = {
  Serviu: "48114",
  MOP: "48115"
};

const subprod  = this.frmIG_idSubProducto;
const diasObra = Number(this.frmDC_diasObra);
const diasMant = Number(this.frmDC_diasMantenimiento);

// Solo para MOP / SERVIU
if (![SUBPRODUCTOS.Serviu, SUBPRODUCTOS.MOP].includes(subprod)) {
  return null;
}

// Validaciones mínimas
if (isNaN(diasObra) || diasObra < 0) return null;
if (isNaN(diasMant) || diasMant < 0) return null;

// Total de días
return diasObra + diasMant;

const SUBPRODUCTOS = {
  Servicios: "48110",
  Construccion: "48111",
  Eventos: "48112",
  Serviu: "48114",
  MOP: "48115"
};

const subproductoId = this.frmIG_idSubProducto;

// Para RC Eventos -> Tipo de Evento
if (subproductoId === SUBPRODUCTOS.Eventos) {
  return "Tipo de Evento";
}

// Para todos los demás productos
return "Actividad Asegurada";
